<?php declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';$admin=vp3_require_admin_permission('settings.manage');if(vp3_method()==='POST'){vp3_verify_csrf();foreach(['support_email','sales_email','default_release_channel'] as $key){$value=vp3_input($key);$stmt=vp3_db()->prepare('INSERT INTO system_settings(setting_key,setting_value,updated_by,created_at,updated_at) VALUES(?,?,?,NOW(),NOW()) ON DUPLICATE KEY UPDATE setting_value=VALUES(setting_value),updated_by=VALUES(updated_by),updated_at=NOW()');$stmt->execute([$key,$value,$admin['id']]);}vp3_audit('admin',(int)$admin['id'],'settings.updated','system_settings',null);vp3_flash('success','Settings updated.');vp3_redirect('admin/settings.php');}$pageTitle='System Settings';require VP3_ROOT.'/includes/admin-header.php';$rows=vp3_db()->query('SELECT setting_key,setting_value FROM system_settings')->fetchAll();$settings=[];foreach($rows as $x)$settings[$x['setting_key']]=$x['setting_value'];?><h1>System settings</h1><form class="card" method="post"><?=vp3_csrf_field()?><div class="field"><label>Support email</label><input name="support_email" type="email" value="<?=vp3_e($settings['support_email']??'support@vp3media.com')?>"></div><div class="field"><label>Sales email</label><input name="sales_email" type="email" value="<?=vp3_e($settings['sales_email']??'sales@vp3media.com')?>"></div><div class="field"><label>Default release channel</label><select name="default_release_channel"><?php foreach(['stable','beta','development'] as $st):?><option <?=($settings['default_release_channel']??'stable')===$st?'selected':''?>><?=$st?></option><?php endforeach;?></select></div><button class="button">Save settings</button></form><?php require VP3_ROOT.'/includes/admin-footer.php';?>